INSERT INTO `client_review` VALUES (63,'요구사항이 명확하고 의사결정이 빨라서 작업하기 좋았습니다! 도메인 지식이 풍부해 많은 도움이 되었고, 피드백도 구체적이고 건설적이었습니다.','2025-01-21 10:00:00.000000',5,1028,1165,3043),(64,'Festory 기획이 명확해서 작업하기 좋았습니다. 사용자 시나리오에 대한 인사이트가 풍부했어요.','2024-09-06 10:00:00.000000',4.8,1028,1168,3043),(65,'Alpha-Helix는 도메인 지식이 깊은 클라이언트와 협업해서 최고의 결과물을 만들 수 있었습니다.','2024-10-11 13:00:00.000000',5,1028,1169,3043),(66,'DevBridge 비전을 명확히 제시해주셔서 개발에 집중할 수 있었습니다. 다음에도 꼭 함께 일하고 싶습니다!','2025-02-12 15:30:00.000000',5,1028,1170,3043);
/*!40000 ALTER TABLE `client_review` ENABLE KEYS */;
UNLOCK TABLES;

