CREATE TABLE `partner_profile` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `avatar_color` varchar(16) DEFAULT NULL,
  `bio` text,
  `bio_file_tag` json DEFAULT NULL,
  `bio_file_url` varchar(1000) DEFAULT NULL,
  `blog_url` varchar(500) DEFAULT NULL,
  `communication_channels` json NOT NULL,
  `dev_experience` enum('EXP_1_3Y','EXP_3_5Y','EXP_5_7Y','OVER_7Y','UND_1Y') NOT NULL,
  `dev_level` enum('JUNIOR','LEAD','MIDDLE','SENIOR_5_7Y','SENIOR_7_10Y') NOT NULL,
  `github_url` varchar(500) DEFAULT NULL,
  `grade` enum('DIAMOND','GOLD','PLATINUM','SILVER') DEFAULT NULL,
  `hashtags` json DEFAULT NULL,
  `short_bio` varchar(200) DEFAULT NULL,
  `hero_key` varchar(30) DEFAULT NULL,
  `job_roles` json NOT NULL,
  `name` varchar(50) DEFAULT NULL,
  `partner_type` enum('CORPORATION','INDIVIDUAL','SOLE_PROPRIETOR','TEAM') NOT NULL,
  `portfolio_file_tag` json DEFAULT NULL,
  `portfolio_file_url` varchar(1000) DEFAULT NULL,
  `preferred_project_type` enum('CONTRACT_BASED','FREELANCE') NOT NULL,
  `salary_hour` int DEFAULT NULL,
  `salary_month` int DEFAULT NULL,
  `service_field` varchar(50) DEFAULT NULL,
  `slogan` varchar(200) NOT NULL,
  `slogan_sub` varchar(255) DEFAULT NULL,
  `strength_desc` text,
  `title` varchar(200) DEFAULT NULL,
  `work_available_hours` json NOT NULL,
  `work_category` enum('DESIGN','DEVELOP','DISTRIBUTION','PLANNING') NOT NULL,
  `work_preference` enum('HYBRID','ONSITE','REMOTE') NOT NULL,
  `youtube_url` varchar(500) DEFAULT NULL,
  `user_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UKbk35mcetfecn6nhpskfk53om` (`user_id`),
  CONSTRAINT `FKlk51tb3dxvcj6i6gch47ax79r` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=2218 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
