INSERT INTO `project_modules` VALUES (7505,NULL,'{\"text\": \"React + Vite 프론트엔드, Spring Boot 백엔드, OpenAI GPT-4 API 통합. 사용자 소비 패턴 분석, 맞춤 투자 추천 알고리즘, 실시간 주식 데이터 연동, 자산 현황 대시보드 구현.\", \"_nego\": {\"workerName\": \"hyleeyou\", \"proposerName\": \"client_hylee\", \"workerUserId\": 3043, \"proposerUserId\": 3044, \"workerAccepted\": true, \"proposerAccepted\": true}}',3043,'hyleeyou','scope',1165,'협의완료','2026-04-24 12:42:07.116232'),(7506,NULL,'{\"text\": \"GitHub 소스코드(프론트+백엔드), 배포된 웹 서비스 URL, OpenAPI 명세(Swagger), 사용자 가이드, ERD 및 시스템 아키텍처 문서, 테스트 케이스 문서.\", \"_nego\": {\"workerName\": \"hyleeyou\", \"proposerName\": \"client_hylee\", \"workerUserId\": 3043, \"proposerUserId\": 3044, \"workerAccepted\": true, \"proposerAccepted\": true}}',3043,'hyleeyou','deliverable',1165,'협의완료','2026-04-24 12:42:11.693043'),(7507,NULL,'{\"text\": \"1단계(기획/설계): 2025.01.15~02.05 / 2단계(핵심 개발): 02.06~05.10 / 3단계(AI 통합/테스트): 05.11~06.30 / 4단계(배포/안정화): 07.01~07.15. 총 6개월.\", \"_nego\": {\"workerName\": \"hyleeyou\", \"proposerName\": \"client_hylee\", \"workerUserId\": 3043, \"proposerUserId\": 3044, \"workerAccepted\": true, \"proposerAccepted\": true}}',3043,'hyleeyou','schedule',1165,'협의완료','2026-04-24 12:42:16.096062'),(7508,NULL,'{\"text\": \"총 계약금액 65,000,000원. ① 착수금(설계 완료 시) 15,000,000원 ② 중도금(핵심 기능 개발 완료 시) 30,000,000원 ③ 잔금(최종 배포 완료 시) 20,000,000원. 마일스톤 검수 후 지급.\", \"_nego\": {\"workerName\": \"hyleeyou\", \"proposerName\": \"client_hylee\", \"workerUserId\": 3043, \"proposerUserId\": 3044, \"workerAccepted\": true, \"proposerAccepted\": true}}',3043,'hyleeyou','payment',1165,'협의완료','2026-04-24 12:42:48.386755'),(7509,NULL,'{\"memo\": \"무상 수정 횟수는 총 3회로 제한됩니다. 횟수 초과 시 또는 유상 수정 기준에 해당하는 요청의 경우, 작업량 산정 후 별도의 추가 비용이 발생할 수 있습니다.\", \"text\": \"최종 납품 후 30일 이내 발견된 버그 무상 수정. 기능 추가 또는 UI 대폭 변경은 별도 견적. 경미한 UI 수정 2회까지 무상 포함.\", \"_nego\": {\"workerName\": \"client_hylee\", \"proposerName\": \"hyleeyou\", \"workerUserId\": 3044, \"proposerUserId\": 3043, \"workerAccepted\": true, \"proposerAccepted\": true}, \"freeItems\": [\"단순 텍스트 문구 및 기배치 이미지의 교체\", \"색상, 폰트 스타일 등 단순 UI/UX 스타일 가이드 조정\", \"기존 기획안의 범주를 벗어나지 않는 마이너 업데이트\"], \"paidItems\": [\"최초 기획에 없던 신규 페이지 제작 및 대규모 기능 추가\", \"프로젝트 전체 디자인 컨셉 및 톤앤매너의 전면 재구축\", \"백엔드 로직의 근본적 변경 또는 DB 스키마 구조의 재설계\"]}',3044,'client_hylee','revision',1165,'협의완료','2026-04-24 12:42:27.305215'),(7510,NULL,'{\"text\": \"핵심 기능(자산 분석, AI 추천, 대시보드) 정상 작동. OpenAI API 응답 시간 5초 이내. 웹 페이지 로딩 속도 Lighthouse 85점 이상. 모바일 반응형 대응.\", \"_nego\": {\"workerName\": \"client_hylee\", \"proposerName\": \"hyleeyou\", \"workerUserId\": 3044, \"proposerUserId\": 3043, \"workerAccepted\": true, \"proposerAccepted\": true}, \"steps\": [{\"n\": 1, \"desc\": \"작업자가 마일스톤 완료 후 결과물을 시스템에 업로드\", \"title\": \"결과물 제출\"}, {\"n\": 2, \"desc\": \"의뢰자의 피드백에 따른 오류 수정 및 보완 작업 진행\", \"title\": \"상호 검수 및 수정\"}, {\"n\": 3, \"desc\": \"모든 조건 충족 시 의뢰자가 최종 완료 버튼 클릭\", \"title\": \"최종 승인 확정\"}], \"criteria\": [\"명세서 기반 기능 전수 동작\", \"주요 브라우저(Chrome, Safari) 호환성 확보\", \"코드 리뷰 인수인계 문서 포함\"], \"categories\": [{\"n\": 1, \"desc\": \"합의된 모든 핵심 및 부가 API의 스웨거(Swagger) 기반 명세서 전달 완료.\", \"title\": \"API 명세서 전달\"}, {\"n\": 2, \"desc\": \"요구사항 상세 정의서(PRD), UI/UX/Figma 디자인 파일 최종안 전달 완료.\", \"title\": \"기획/UI/UX 정밀 검수, 문서 첨부\"}, {\"n\": 3, \"desc\": \"Github 프라이빗 리포지토리의 모든 개발 코드 및 배포 스크립트 최종 푸시 완료.\", \"title\": \"소스코드 리포지토리 전달\"}, {\"n\": 4, \"desc\": \"합의된 테스트 시나리오에 따른 QA 및 베타 테스터 결과 보고서 제출 및 버그 수정 완료.\", \"title\": \"운영 환경 테스트 완료\"}]}',3044,'client_hylee','completion',1165,'협의완료','2026-04-24 12:42:31.971734'),(7511,NULL,'{\"text\": \"개발 완료 후 소스코드 전체 클라이언트 이관. 2개월 무상 유지보수 및 기술 지원 포함. OpenAI API 키는 클라이언트 제공. 배포 서버는 클라이언트 계정으로 AWS 사용.\", \"_nego\": {\"workerName\": \"client_hylee\", \"proposerName\": \"hyleeyou\", \"workerUserId\": 3044, \"proposerUserId\": 3043, \"workerAccepted\": true, \"proposerAccepted\": true}, \"intro\": \"프로젝트의 원활한 진행과 상호 권리 보호를 위해 아래의 추가 특약 사항을 협의합니다.\", \"terms\": [{\"id\": \"nda\", \"icon\": \"🛡\", \"items\": [\"프로젝트 관련 모든 내부 자료 및 산출물에 대한 제3자 유출 금지\", \"위반 시 발생한 실제 손해에 대한 배상 책임 부담\"], \"title\": \"보안 및 기밀 유지 (NDA)\", \"enabled\": true}, {\"id\": \"ip\", \"icon\": \"©\", \"items\": [\"최종 대금 지급 완료 시 산출물에 대한 모든 저작권은 의뢰인에게 귀속\", \"단, 작업자의 비상업적 목적 포트폴리오 활용 권한은 인정\"], \"title\": \"지식재산권 귀속\", \"enabled\": true}, {\"id\": \"dispute\", \"icon\": \"⚖\", \"items\": [\"발생하는 분쟁은 상호 협의를 통해 해결함을 원칙으로 하되, 원만히 해결되지 않을 경우 서울중앙지방법원을 전합 관할로 합니다.\"], \"title\": \"분쟁 해결 및 관할\", \"enabled\": false}, {\"id\": \"other\", \"icon\": \"···\", \"items\": [\"Communication: 계약 기간 내 상호 비방 금지 및 신의성실 원칙 준수\", \"Handover: 프로젝트 종료 후 인수인계 기간 최소 1주일 보장\"], \"title\": \"기타 특약\", \"enabled\": false}]}',3044,'client_hylee','terms',1165,'협의완료','2026-04-24 12:42:36.462366'),(7512,NULL,'{\"memo\": \"레거시 시스템과의 연결을 고려한 설계 포함\\n운영 환경 인프라 설정은 제외\", \"text\": \"기존 결제 시스템 성능 개선 및 보안 강화. PG사 멀티 연동(토스페이먼츠, 나이스페이), 결제 취소/환불 로직 고도화, 트랜잭션 로그 모니터링 시스템 구축, 부정 결제 탐지 알고리즘 적용.\", \"_nego\": {\"proposerName\": \"client_hylee\", \"proposerUserId\": 3044, \"workerAccepted\": false, \"proposerAccepted\": true}, \"excluded\": [\"프론트엔드 개발\", \"서버 배포\", \"운영 중 장애 대응\"], \"included\": [\"GraphQL schema 설계\", \"API 구조 정리\", \"기존 REST API 일부 리팩토링\"]}',3044,'client_hylee','scope',1166,'제안됨','2026-04-24 14:28:09.371668'),(7513,NULL,'{\"text\": \"개선된 결제 모듈 소스코드, API 명세서(Swagger), 부하 테스트 리포트(k6/JMeter), 보안 점검 리포트, 운영 매뉴얼, 장애 대응 가이드.\", \"_nego\": {\"proposerName\": \"hyleeyou\", \"proposerUserId\": 3043, \"workerAccepted\": false, \"proposerAccepted\": true}, \"notes\": [\"전달물은 한글 설명 문서 포함\", \"배포본은 포함되지 않음\"], \"formats\": [\"PDF\", \".graphql 또는 .txt\", \"GitHub URL\"], \"delivery\": [\"DevBridge 채팅 첨부\", \"GitHub 링크 공유\", \"필요 시 ZIP 파일 별도 전달\"], \"deliverables\": [{\"icon\": \"📄\", \"label\": \"API 설계 문서 PDF 1부\"}, {\"icon\": \"📝\", \"label\": \"GraphQL schema 파일\"}, {\"icon\": \"🔗\", \"label\": \"GitHub repository 링크\"}, {\"icon\": \"📖\", \"label\": \"간단한 적용 가이드 문서\"}]}',3043,'hyleeyou','deliverable',1166,'제안됨','2026-04-24 14:28:23.235886'),(7514,NULL,'{\"text\": \"1단계(분석/설계): 2025.02.01~02.1