DROP TABLE IF EXISTS `projects`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `projects` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `additional_comment` text,
  `additional_file_url` varchar(1000) DEFAULT NULL,
  `avatar_color` varchar(16) DEFAULT NULL,
  `budget_amount` int DEFAULT NULL,
  `budget_max` int DEFAULT NULL,
  `budget_min` int DEFAULT NULL,
  `category` json DEFAULT NULL,
  `collab_design` int DEFAULT NULL,
  `collab_dev` int DEFAULT NULL,
  `collab_planning` int DEFAULT NULL,
  `collab_publishing` int DEFAULT NULL,
  `contract_months` int DEFAULT NULL,
  `created_at` datetime(6) DEFAULT NULL,
  `current_stacks` json DEFAULT NULL,
  `current_status` text,
  `deadline` date DEFAULT NULL,
  `desc` text,
  `detail_content` text,
  `dev_stage` enum('BETA','DEVELOPMENT','MAINTENANCE','OPERATING','PLANNING') DEFAULT NULL,
  `duration_months` int DEFAULT NULL,
  `gov_support` bit(1) DEFAULT NULL,
  `grade` enum('DIAMOND','GOLD','PLATINUM','SILVER') DEFAULT NULL,
  `is_partner_free` bit(1) DEFAULT NULL,
  `it_exp` bit(1) DEFAULT NULL,
  `meeting_freq` enum('BIWEEKLY','DAILY','MONTHLY','WEEKLY') DEFAULT NULL,
  `meeting_tools` json DEFAULT NULL,
  `meeting_type` enum('HYBRID','OFFLINE','ONLINE') DEFAULT NULL,
  `monthly_rate` int DEFAULT NULL,
  `outsource_project_type` enum('MAINTENANCE','NEW') DEFAULT NULL,
  `project_type` enum('FULLTIME','OUTSOURCE') NOT NULL,
  `questions` json DEFAULT NULL,
  `ready_status` enum('CODE','DESIGN','DOCUMENT','IDEA') DEFAULT NULL,
  `reference_file_url` varchar(1000) DEFAULT NULL,
  `req_tags` json DEFAULT NULL,
  `schedule_negotiable` bit(1) DEFAULT NULL,
  `service_field` varchar(50) DEFAULT NULL,
  `slogan` varchar(255) DEFAULT NULL,
  `slogan_sub` varchar(255) DEFAULT NULL,
  `start_date` date DEFAULT NULL,
  `start_date_negotiable` bit(1) DEFAULT NULL,
  `status` enum('CLOSED','COMPLETED','IN_PROGRESS','RECRUITING') DEFAULT NULL,
  `team_size` enum('SIZE_11_30','SIZE_1_5','SIZE_31_50','SIZE_50_PLUS','SIZE_6_10') DEFAULT NULL,
  `title` varchar(255) NOT NULL,
  `updated_at` datetime(6) DEFAULT NULL,
  `visibility` enum('APPLICANTS','PRIVATE','PUBLIC') DEFAULT NULL,
  `work_days` enum('FIVE_DAYS','FLEXIBLE','FOUR_DAYS','THREE_DAYS') DEFAULT NULL,
  `work_hours` enum('AFTERNOON','FLEXIBLE','FULLTIME','MORNING') DEFAULT NULL,
  `work_location` varchar(255) DEFAULT NULL,
  `work_scope` json DEFAULT NULL,
  `work_style` enum('HYBRID','ONSITE','REMOTE') DEFAULT NULL,
  `user_id` bigint NOT NULL,
  `contract_terms` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `FKhswfwa3ga88vxv1pmboss6jhm` (`user_id`),
  CONSTRAINT `FKhswfwa3ga88vxv1pmboss6jhm` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
