  `projects` json DEFAULT NULL,
  `role` varchar(100) DEFAULT NULL,
  `sort_order` int DEFAULT NULL,
  `start_date` varchar(20) DEFAULT NULL,
  `verified_company` bit(1) DEFAULT NULL,
  `verified_email` varchar(255) DEFAULT NULL,
  `user_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `FK11gdf9epyywr3kpgem0uja8on` (`user_id`),
  CONSTRAINT `FK11gdf9epyywr3kpgem0uja8on` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
